command.text:
declare @message nvarchar(4000) select @message = ''
&CommandControlLocationLotShowing;
select @message as message return

script.text:

/* <flatten type="Javascript"> */
function load$GridVoucherDetail$(g) {
  g.add_itemValueChanged(onChange$GridVoucherDetail$);
  g.add_onResponseComplete(on$GridVoucherDetail$ResponseComplete);
  g.add_commandEvent(on$GridVoucherDetail$ExecuteCommand);
  g.$a = {
    gia_nt_sl: '[gia_nt]:=([gia_nt] == 0 ? ([so_luong] != 0 ? ([tien_nt]/[so_luong]) : 0) : [gia_nt])',
    gia_sl: '[gia]:=([gia] == 0 ? ([so_luong] != 0 ? ([tien]/[so_luong]) : 0) : [gia])',

    gia_tg: '[gia]:=[gia_nt]*[$ty_gia]',
    tien_nt: '[tien_nt]:=[so_luong]*[gia_nt]',
    tien: '[tien]:=[so_luong]*[gia]',
    tien_tg: '[tien]:=[tien_nt]*[$ty_gia]',

    t_tien_nt: ['t_tien_nt', 'tien_nt'],
    t_tien: ['t_tien', 'tien'],

    t_tt_nt: '[t_tt_nt]:=[t_tien_nt]+[t_thue_nt]',
    t_tt: '[t_tt]:=[t_tien]+[t_thue]'
  };
  g.$h = [['voucherCode', 'String', g._voucherCode], 'ma_kh', 'ngay_lct', 'ma_tt', 'ma_nt', 'ma_dvcs'];
  udf$Detail$(g, true);
}
function dispose$GridVoucherDetail$(g) {
  g.$a = null;
  try {g.remove_commandEvent(on$GridVoucherDetail$ExecuteCommand);} catch (ex) {}
  try {g.remove_onResponseComplete(on$GridVoucherDetail$ResponseComplete);} catch (ex) {}
  try {g.remove_itemValueChanged(onChange$GridVoucherDetail$);} catch (ex) {}
}
function onChange$GridVoucherDetail$Item(o) {o.grid.request(o, 'Item', 'Item', ['ma_vt', 'ma_kho'], o.grid.$h, true);}
function onChange$GridVoucherDetail$UOM(o) {o.grid.request(o, 'UOM', 'UOM', ['ma_vt', 'ma_kho', 'dvt', 'so_luong'], o.grid.$h, true);}
function onChange$GridVoucherDetail$Site(o) {o.grid.request(o, 'Site', 'Site', ['ma_vt','ma_kho'], o.grid.$h, true);}
function onChange$GridVoucherDetail$(sender, eventArgs) {
  var o = eventArgs.get_object(), g = o.grid, f = g.get_element().parentForm, name = o.field.Name;
  switch (name) {
    case 'so_luong':
      g.validExpression(o, [g.$a.tien_nt, g.$a.tien], [g.$a.t_tien_nt, g.$a.t_tien], [g.$a.t_tt_nt, g.$a.t_tt], 'gia_nt');
      break;
    case 'gia_nt':
      g.validExpression(o, [g.$a.gia_tg, g.$a.tien_nt, g.$a.tien], [g.$a.t_tien_nt, g.$a.t_tien], [g.$a.t_tt_nt, g.$a.t_tt], 'tien_nt');
      break;
    case 'gia':
      g.validExpression(o, [g.$a.tien], [g.$a.t_tien], [g.$a.t_tt], 'tien');
      break;
    case 'tien_nt':
      if (f._calPrice) g.validExpression(o, [g.$a.gia_nt_sl, g.$a.gia_tg]);
      g.validExpression(o, [g.$a.tien_tg], [g.$a.t_tien_nt, g.$a.t_tien], [g.$a.t_tt_nt, g.$a.t_tt]);
      break;
    case 'tien':
      if (f._calPrice) g.validExpression(o, [g.$a.gia_sl]);
      g.validExpression(o, null, [g.$a.t_tien], [g.$a.t_tt]);
      break;
    default:
      break;
  }
}
/* </flatten> */
function on$GridVoucherDetail$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender, f = g.get_element().parentForm;
  switch (action) {&ScriptCheckGridAction;
    case 'AfterRemoveRow':
      on$GridVoucherDetail$RowChange(g, f);
      break;
    case 'AfterCloneRow':
      g.setItemFieldValue('stt_rec0', e.type.Value, '');
      on$GridVoucherDetail$RowChange(g, f);
      break;
    case 'Check':
      if (g._tracked$Lot && !(g.validRowExpression('ma_lo', '(![lo_yn]) || ([ma_lo] != "")'))) break;
      if (g._tracked$Location) g.validRowExpression('ma_vi_tri', '(![vi_tri_yn]) || ([ma_vi_tri] != "")');
      break;
    case 'Retrieve':
      if (f._action == 'View') break;
      if (!f.validFields('ma_kh, ngay_lct')) break;
      if (f._action != 'View') g.showForm('PAInvoiceFilter');
      break;
    case 'Copying':
      set$Voucher$EmptyExternalField(g, 'hd_so, hd_ln, stt_rec_hd, stt_rec0hd');
      break;
    default:
      break;
  }
}
/* <flatten type="Javascript"> */
function on$GridVoucherDetail$ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result, o = e.type.Object, f = g.get_element().parentForm;
  switch (context) {
    case 'Item':
      var v = (result[0].Value == '' ? true : null), t = (result[0].Value == '' ? 'false' : 'true');
      g.setItemGridBehavior(o, [
        ['ma_lo', '', null, null],
        ['ma_kho', result[0].Value, '', true],
        ['ma_vi_tri', result[1].Value, '', v],
        ['dvt', result[2].Value, '', true],
        ['he_so', result[3].Value, null, null],
        ['tk_vt', result[4].Value, '', true],
        ['gia_ton', result[5].Value, null, null],
        ['vi_tri_yn', [result[6].Value, t], null, null],
        ['lo_yn', result[7].Value, null, null]
      ]);
      g.live(o, 'dvt');
      break;
    case 'UOM':
      g.setItemGridBehavior(o, [['he_so', result[0].Value, '', true]]);
      break;
    case 'Site':
      g.setItemGridBehavior(o, [['tk_vt', result[0].Value, '', true], ['ma_vi_tri', '', '', null], ['vi_tri_yn', result[1].Value, null, null]]);
      break;
    default:
      break;
  }
}
function on$GridVoucherDetail$RowChange(g, f) {
  g.executeAggregate([g.$a.t_tien_nt, g.$a.t_tien]);
  f.executeExpression([g.$a.t_tt_nt, g.$a.t_tt]);
}
/* </flatten> */

      &ScriptInsertRetrieveItems;
      &ScriptEmptyExternalField;

grid.response:
&XMLGetUOMConversion;
if exists(select 1 from dmvt where ma_vt = @ma_vt) begin declare @unitCode varchar(32) select @unitCode = case when @$ma_dvcs = '' then @@unit else @$ma_dvcs end exec FastBusiness$Voucher$Receipt$Item @unitCode, @ma_vt, @voucherCode, @@userID, @@admin, @ma_kho return end
declare @unitCode varchar(32) select @unitCode = case when @$ma_dvcs = '' then @@unit else @$ma_dvcs end if exists(select 1 from dmkho where ma_kho = @ma_kho and ma_dvcs = @unitCode&SiteCheck;) begin exec FastBusiness$Voucher$Receipt$Site @unitCode, @ma_vt, @ma_kho return end
